cat > /tmp/binlog-reader/Program.cs << 'EOF'
using System;
using Microsoft.Build.Logging.StructuredLogger;

var binlogPath = args[0];
var build = BinaryLog.ReadBuild(binlogPath);

Console.WriteLine("=== ALL ERRORS (with full context) ===");
build.VisitAllChildren<Error>(error => {
    var parent = error.Parent;
    string targetName = "";
    while (parent != null) {
        if (parent is Target t) { targetName = t.Name; break; }
        parent = parent.Parent;
    }
    Console.WriteLine($"Project: {error.ProjectFile}");
    Console.WriteLine($"  Target: {targetName}");
    Console.WriteLine($"  File: {error.File}");
    Console.WriteLine($"  Line: {error.LineNumber}, Col: {error.ColumnNumber}");
    Console.WriteLine($"  Code: {error.Code}");
    Console.WriteLine($"  Text: {error.Text}");
    Console.WriteLine($"  Subcategory: {error.Subcategory}");
    Console.WriteLine();
});

Console.WriteLine("\n=== PROJECT BUILD ORDER & RESULTS ===");
build.VisitAllChildren<Project>(project => {
    Console.WriteLine($"  Project: {project.ProjectFile} | Name: {project.Name}");
    // Check for errors in children
    bool hasErrors = false;
    project.VisitAllChildren<Error>(e => hasErrors = true);
    Console.WriteLine($"    Has errors: {hasErrors}");
});

// Also check for source files embedded
Console.WriteLine("\n=== SOURCE FILE CONTENT FROM BINLOG ===");
build.VisitAllChildren<CscTask>(task => {
    Console.WriteLine($"  Csc task in: {task.ProjectFile}");
    Console.WriteLine($"  CommandLine: {task.CommandLineArguments?.Substring(0, Math.Min(500, task.CommandLineArguments?.Length ?? 0))}");
    Console.WriteLine();
});
EOF

