cat > /tmp/binlog-reader/Program.cs << 'EOF'
using System;
using System.IO;
using System.IO.Compression;
using Microsoft.Build.Logging.StructuredLogger;

var binlogPath = args[0];
var build = BinaryLog.ReadBuild(binlogPath);

// Check SourceFilesArchive (it's a byte[] that's a zip archive)
Console.WriteLine("=== SOURCE FILES IN BINLOG ===");
var archive = build.SourceFilesArchive;
if (archive != null && archive.Length > 0) {
    using var ms = new MemoryStream(archive);
    using var zip = new ZipArchive(ms, ZipArchiveMode.Read);
    foreach (var entry in zip.Entries) {
        Console.WriteLine($"\n=== FILE: {entry.FullName} ===");
        using var reader = new StreamReader(entry.Open());
        Console.WriteLine(reader.ReadToEnd());
    }
} else {
    Console.WriteLine("No embedded source files found");
}

// Also look for CscCommandLineArgs to see what references were provided
Console.WriteLine("\n=== CSC COMMAND LINE ARGS ===");
build.VisitAllChildren<Task>(task => {
    if (task.Name == "Csc") {
        var parent = task.Parent;
        string projFile = "";
        while (parent != null) {
            if (parent is Project p) { projFile = p.ProjectFile; break; }
            parent = parent.Parent;
        }
        Console.WriteLine($"\nCsc in project: {projFile}");
        // Look for CommandLineArguments in children
        task.VisitAllChildren<Message>(msg => {
            if (msg.Text != null && msg.Text.Contains("/reference:")) {
                Console.WriteLine($"  References mentioned: {msg.Text.Substring(0, Math.Min(500, msg.Text.Length))}");
            }
        });
    }
});
EOF

