cat > /tmp/binlog-reader/Program.cs << 'EOF'
using System;
using System.Linq;
using Microsoft.Build.Logging.StructuredLogger;

var binlogPath = args[0];
var build = BinaryLog.ReadBuild(binlogPath);

// Check which projects actually built vs were skipped  
Console.WriteLine("=== BUILD TARGETS & RESULTS ===");
int projCount = 0;
build.VisitAllChildren<Project>(project => {
    projCount++;
    // Only look at the Build target invocations
    bool hasBuildTarget = false;
    bool hasCompileTarget = false;
    project.VisitAllChildren<Target>(target => {
        if (target.Name == "Build") hasBuildTarget = true;
        if (target.Name == "CoreCompile") hasCompileTarget = true;
    });

    bool hasErrors = false;
    project.VisitAllChildren<Error>(e => hasErrors = true);

    if (hasBuildTarget || hasCompileTarget || hasErrors) {
        Console.WriteLine($"  #{projCount} {project.Name} (Build target: {hasBuildTarget}, CoreCompile: {hasCompileTarget}, HasErrors: {hasErrors})");
    }
});

// Show overall build result
Console.WriteLine($"\n=== OVERALL BUILD SUCCEEDED: {build.Succeeded} ===");

// Look for "skipped" or "not built" messages for Api  
Console.WriteLine("\n=== MESSAGES ABOUT Api PROJECT ===");
build.VisitAllChildren<Message>(msg => {
    if (msg.Text != null && msg.Text.Contains("Api") && (msg.Text.Contains("skip") || msg.Text.Contains("not") || msg.Text.Contains("depend") || msg.Text.Contains("fail"))) {
        Console.WriteLine($"  {msg.Text}");
    }
});
EOF

